	private static final class CountingSketchBasedJoinEstimator extends SketchBasedJoinEstimator {
		private int sketchJoinEstimateCalls;

		private CountingSketchBasedJoinEstimator(SailStore sailStore, Config cfg) {
			super(sailStore, cfg);
		}

		@Override
		JoinStepEstimate estimateJoinStepForJoinOrdering(TuplePlanEstimate left, TuplePlanEstimate right) {
			sketchJoinEstimateCalls++;
			return super.estimateJoinStepForJoinOrdering(left, right);
		}

		@Override
		JoinStepEstimate estimateJoinStepForJoinOrdering(TuplePlanEstimate left, TuplePlanEstimate right,
				JoinOrderingSketchIntersectionCache sketchIntersectionCache) {
			sketchJoinEstimateCalls++;
			return super.estimateJoinStepForJoinOrdering(left, right, sketchIntersectionCache);
		}
	}

	private static ListMemberOperator listMemberCondition(String varName, int... values) {
		ListMemberOperator operator = new ListMemberOperator();
		operator.addArgument(Var.of(varName));
		for (int value : values) {
			operator.addArgument(new ValueConstant(VF.createLiteral(value)));
		}
		return operator;
	}

	private static SketchBasedJoinEstimator.Config config() {
		return SketchBasedJoinEstimator.Config.defaults()
				.withNominalEntries(64)
				.withThrottleEveryN(1)
				.withThrottleMillis(0)
				.withRefreshSleepMillis(5);
	}

	private static void assertPlanWorkMatchesStepSum(JoinOrderPlanner.JoinOrderPlan plan) {
		assertTrue(Double.isFinite(plan.getEstimatedTotalWork()), "Estimated plan work should be finite");
		assertTrue(plan.getEstimatedTotalWork() >= 0.0d, "Estimated plan work should be non-negative");
		if (!plan.getSteps().isEmpty()) {
			double stepWorkSum = plan.getSteps()
					.stream()
					.mapToDouble(JoinOrderPlanner.PlanStep::getStepWorkRows)
					.sum();
			double tolerance = Math.max(0.0001d, Math.abs(plan.getEstimatedTotalWork()) * 1.0e-9d);
			assertEquals(stepWorkSum, plan.getEstimatedTotalWork(), tolerance,
					"Estimated total work should equal the sum of step work");
		}
	}

	private static StatementPattern pattern(String subjVar, IRI pred, String objVar) {
		return new StatementPattern(Var.of(subjVar), Var.of("p", pred), Var.of(objVar));
	}

	private static QueryBindingSet row(String name1, org.eclipse.rdf4j.model.Value value1, String name2,
			org.eclipse.rdf4j.model.Value value2) {
		QueryBindingSet row = new QueryBindingSet();
		row.addBinding(name1, value1);
		row.addBinding(name2, value2);
		return row;
	}

	@SuppressWarnings("unchecked")
	private static Map<String, Object> varStats(SketchBasedJoinEstimator.TuplePlanEstimate estimate) {
		try {
			Field field = SketchBasedJoinEstimator.TuplePlanEstimate.class.getDeclaredField("varStats");
			field.setAccessible(true);
			return (Map<String, Object>) field.get(estimate);
		} catch (ReflectiveOperationException e) {
			throw new AssertionError(e);
		}
	}

	private static int estimateCacheSize(SketchBasedJoinEstimator estimator) {
		try {
			Field field = SketchBasedJoinEstimator.class.getDeclaredField("estimateCache");
			field.setAccessible(true);
			return ((Map<?, ?>) field.get(estimator)).size();
		} catch (ReflectiveOperationException e) {
			throw new AssertionError(e);
		}
	}
